
-- Step 1: Delete all wrong/fake Computer Science courses (those not in the CCMAS 2025-2026 handbook)
-- COS 101 has data so we keep it. We delete all fabricated courses.
DELETE FROM courses WHERE department = 'Computer Science' AND code IN (
  'CSC 100', 'COS 203', 'COS 204', 'COS 205', 'COS 206', 'COS 207', 'COS 208',
  'CSC 227', 'STA 201',
  'COS 301', 'COS 302', 'COS 303', 'COS 304', 'COS 305', 'COS 306', 'COS 307', 'COS 308', 'COS 309', 'COS 310', 'COS 399',
  'COS 401', 'COS 402', 'COS 403', 'COS 404', 'COS 405', 'COS 406', 'COS 407', 'COS 408', 'COS 410', 'COS 498', 'COS 499'
);

-- Step 2: Update existing courses that have wrong data
-- Fix PHY 101 units (3 -> 2)
UPDATE courses SET units = 2, description = 'Mechanics: Space and time, vectors and scalars, kinematics, Newton''s laws of motion, conservation principles, rotational motion, gravitation.', overview = 'Space and time; units and dimension, Vectors and Scalars, Differentiation of vectors: displacement, velocity and acceleration; kinematics; Newton laws of motion; Relative motion; Conservation principles in physics; Rotational motion; Gravitation: Newton''s Law of Gravitation, Kepler''s Laws.' WHERE code = 'PHY 101' AND department = 'Computer Science';

-- Fix PHY 102 units (3 -> 2)
UPDATE courses SET units = 2, code = 'PHY 102', description = 'Electricity & Magnetism: Electrostatics, Coulomb''s law, Gauss''s law, capacitance, DC circuits, magnetic fields, electromagnetic induction, Maxwell''s equations, AC circuits.', overview = 'Forces in nature. Electrostatics. Coulomb''s law and superposition. Electric field and potential. Gauss''s law. Capacitance. DC circuits. Magnetic fields. Electromagnetic induction. Maxwell''s equations. AC voltages and currents.' WHERE code = 'PHY 102' AND department = 'Computer Science';

-- Fix GST 212 semester (First -> Second) 
UPDATE courses SET semester = 'Second', description = 'Philosophy, Logic and Human Existence: branches of philosophy, logic, syllogism, symbolic logic, informal fallacies, valid and invalid arguments, critical thinking.', overview = 'Notions, meanings, branches and problems of philosophy. Logic as an indispensable tool of philosophy. Elements of syllogism, symbolic logic. Informal fallacies, laws of thought. Valid and invalid arguments. Creative and critical thinking. Impact of philosophy on human existence.' WHERE code = 'GST 212' AND department = 'Computer Science';

-- Fix ENT 211 (make sure it's in correct semester)
UPDATE courses SET semester = 'First', level = '200', description = 'Entrepreneurship and Innovation: concepts, theories, characteristics of entrepreneurs, entrepreneurial thinking, innovation, enterprise formation, e-commerce.', overview = 'Concept of Entrepreneurship. Theories, Rationale and relevance. Characteristics of Entrepreneurs. Entrepreneurial thinking. Innovation. Enterprise formation, partnership and networking. Contemporary Entrepreneurship Issues. Basic principles of e-commerce.' WHERE code = 'ENT 211' AND department = 'Computer Science';

-- Update COS 101 description from handbook
UPDATE courses SET description = 'Introduction to computing: basic components, applications, information processing, the Internet, computing discipline areas and specializations.', overview = 'Brief history of computing. Description of basic components of a computer. Input/Output devices. Hardware, software and human ware. Computer applications. Information processing and its roles in society. The Internet and its applications. Different areas of the computing discipline. Job specializations for computing professionals.' WHERE code = 'COS 101' AND department = 'Computer Science';

-- Update COS 102
UPDATE courses SET description = 'Problem solving processes and skills, algorithms, flowcharts, pseudocode, and programming in C/Python.', overview = 'Introduction to core concepts of computing. Problems and problem-solving. Method of solving computing problems. Solvable and unsolvable problems. Solution techniques. General problem-solving process. Solution formulation: flowchart, pseudocode, decision table. Implementation and refinement. Programming in C, Python.' WHERE code = 'COS 102' AND department = 'Computer Science';

-- Update COS 201
UPDATE courses SET description = 'Principles of programming: structured programming, OOP concepts, data types, control structures, arrays, recursion, inheritance, polymorphism.', overview = 'Essentials of computer programming. Types of programming. Scripting languages. Structured programming principles. Basic data types, variables, expressions. Basic OOP concepts: abstraction, objects, classes, methods, encapsulation. Class hierarchies. Searching, sorting, recursive algorithms. Event-driven programming. Strings and I/O.' WHERE code = 'COS 201' AND department = 'Computer Science';

-- Update COS 202
UPDATE courses SET description = 'Advanced OOP: polymorphism, abstract classes, interfaces, API usage, searching, sorting, recursion, event-driven and GUI programming.', overview = 'Review of advanced OOP - polymorphism, abstract classes and interfaces. Class hierarchies using packages/namespaces. API usage. Searching, sorting, recursive algorithms. Event-driven programming. Exception handling. GUI programming.' WHERE code = 'COS 202' AND department = 'Computer Science';

-- Update COS 409
UPDATE courses SET units = 3, description = 'Research methodology: types, approaches, data collection methods, questionnaire design, report writing, sampling design, data analysis.', overview = 'Foundations of Research. Types and approaches. Research Methods vs Methodology. Research Process. Scientific investigation. Problem formulation. Data Collection methods. Guidelines for constructing questionnaires. Research Proposal and Plan. Technical Report Writing. Sampling Design. Data Analysis.' WHERE code = 'COS 409' AND department = 'Computer Science';

